#include<bits/stdc++.h>
using namespace std;
const int MAXN = 5e5 + 10;
long long ans[MAXN];
map<int,int>m;
int t[MAXN];
int main()
{
	// freopen("list.in","r",stdin);
	// freopen("list.out","w",stdout);
	int n,m;
	cin >> n >> m;
	int size = 0;
	for(int i = 0; i < n; i++){
		string a;
		cin >> a;
		int x = 0;
		for(int i = 0; i < a.size(); i++){
			x = x * 10 + (a[i] - '0');
		}
		if(!t[x]){
			size += a.size() + 1;
		}
		t[x] = 1;
//		cout << s.size() << endl;
		ans[x] = size;
	}
//	cout << 1;
	for(int i = 1; i <= m; i++){
		cout << ans[i] - 1 << " ";
	}
}
